module div_8bit (
    input wire clk,
    input wire rst,
    input wire [7:0] dividend,
    input wire [7:0] divisor,
    input wire sign,
    input wire opn_valid,
    output reg res_valid,
    input wire res_ready,
    output wire [15:0] result
);

parameter DIVIDE = 1'b1;
parameter IDLE = 1'b0;

reg state, next_state;
reg [3:0] cnt;
reg [8:0] neg_divisor;
reg [8:0] remainder;
reg [7:0] quotient;
reg [16:0] SR;
reg [8:0] sub_result;
reg [8:0] mux_out;
reg [8:0] temp_remainder;
reg [7:0] temp_quotient;
reg [8:0] final_remainder;
reg [7:0] final_quotient;
reg carry_in;
reg start_cnt;

always @(posedge clk or posedge rst) begin
    if (rst) begin
        state <= IDLE;
    end else begin
        state <= next_state;
    end
end

always @(*) begin
    case (state)
        DIVIDE: begin
            if (cnt == 4'd8) begin
                next_state = IDLE;
            end else begin
                next_state = DIVIDE;
            end
        end
        default: begin
            if (opn_valid && !res_valid) begin
                next_state = DIVIDE;
            end else begin
                next_state = IDLE;
            end
        end
    endcase
end

always @(posedge clk or posedge rst) begin
    if (rst) begin
        cnt <= 4'd0;
    end else if (start_cnt) begin
        cnt <= cnt + 1;
    end else begin
        cnt <= 4'd0;
    end
end

always @(posedge clk or posedge rst) begin
    if (rst) begin
        neg_divisor <= 9'd0;
    end else if (sign) begin
        neg_divisor <= {~divisor[7], ~divisor} + 9'd1;
    end else begin
        neg_divisor <= {1'b0, divisor};
    end
end

always @(posedge clk or posedge rst) begin
    if (rst) begin
        remainder <= 9'd0;
    end else if (state == DIVIDE) begin
        remainder <= sub_result;
    end else begin
        remainder <= 9'd0;
    end
end

always @(posedge clk or posedge rst) begin
    if (rst) begin
        quotient <= 8'd0;
    end else if (state == DIVIDE) begin
        quotient[cnt] <= mux_out[8];
    end else begin
        quotient <= 8'd0;
    end
end

always @(posedge clk or posedge rst) begin
    if (rst) begin
        SR <= 17'd0;
    end else if (state == DIVIDE) begin
        SR <= {mux_out[7:0], SR[8]};
    end else begin
        SR <= {1'b0, dividend, 8'd0};
    end
end

assign sub_result = {1'b0, SR[16:9]} + neg_divisor;

assign mux_out = (sub_result[8]) ? temp_remainder : temp_quotient;

assign carry_in = (sub_result[8]) ? 1'b0 : 1'b1;

always @(posedge clk or posedge rst) begin
    if (rst) begin
        temp_remainder <= 9'd0;
    end else if (state == DIVIDE) begin
        temp_remainder <= {sub_result[7:0], SR[8]};
    end else begin
        temp_remainder <= 9'd0;
    end
end

always @(posedge clk or posedge rst) begin
    if (rst) begin
        temp_quotient <= 8'd0;
    end else if (state == DIVIDE) begin
        temp_quotient[cnt] <= 1'b0;
    end else begin
        temp_quotient <= 8'd0;
    end
end

always @(posedge clk or posedge rst) begin
    if (rst) begin
        final_remainder <= 9'd0;
    end else if (state == DIVIDE && cnt == 4'd8) begin
        final_remainder <= temp_remainder;
    end else begin
        final_remainder <= 9'd0;
    end
end

always @(posedge clk or posedge rst) begin
    if (rst) begin
        final_quotient <= 8'd0;
    end else if (state == DIVIDE && cnt == 4'd8) begin
        final_quotient <= temp_quotient;
    end else begin
        final_quotient <= 8'd0;
    end
end

assign result = {final_remainder, final_quotient};

always @(posedge clk or posedge rst) begin
    if (rst) begin
        start_cnt <= 1'b0;
    end else if (opn_valid && !res_valid) begin
        start_cnt <= 1'b1;
    end else begin
        start_cnt <= 1'b0;
    end
end

always @(posedge clk or posedge rst) begin
    if (rst) begin
        res_valid <= 1'b0;
    end else if (cnt == 4'd8) begin
        res_valid <= 1'b1;
    end else if (res_valid && res_ready) begin
        res_valid <= 1'b0;
    end else begin
        res_valid <= res_valid;
    end
end
endmodule
